import jsPDF from "jspdf";
import React from "react";
import { useNavigate } from "react-router";
import useAuth from "../../Hooks/useAuth";
import { useQuery } from "@tanstack/react-query";
import useAxiosSecure from "../../Hooks/useAxiosSecure";

const PaymentSuccess = () => {
  const navigate = useNavigate();
  const { user } = useAuth();
  const axiosSecure = useAxiosSecure();
  console.log(user);

  const { data: usersPaymentDetails = [] } = useQuery({
    queryKey: ["payments", user?.email],
    enabled: !!user?.email,
    queryFn: async () => {
      const res = await axiosSecure.get(`/payments?email=${user?.email}`);
      return res.data;
    },
  });

  console.log(usersPaymentDetails);

  const handleDownloadPDF = () => {
    const doc = new jsPDF();

    // 🖼️ Logo (base64 image লাগবে)
    const logo =
      "data:image/jpeg;base64,"; // 👉 এখানে তোমার logo বসাও

    // 🟦 Header Background
    doc.setFillColor(0, 102, 204); // Blue
    doc.rect(0, 0, 210, 30, "F");

    // 🖼️ Logo Add
    doc.addImage(logo, "PNG", 10, 5, 20, 20);

    // 🏷️ Title
    doc.setFontSize(18);
    doc.setTextColor(255, 255, 255);
    doc.text("PAYMENT RECEIPT", 105, 18, null, null, "center");

    // 🔲 Top Info Cards
    doc.setFillColor(240, 248, 255); // light blue
    doc.roundedRect(20, 40, 50, 20, 3, 3, "F");
    doc.roundedRect(75, 40, 50, 20, 3, 3, "F");
    doc.roundedRect(130, 40, 60, 20, 3, 3, "F");

    doc.setTextColor(0, 0, 0);
    doc.setFontSize(10);

    doc.text("Receipt No", 25, 48);
    doc.text("Date", 80, 48);
    doc.text("Payment", 135, 48);

    doc.setFontSize(11);
    doc.text("123456", 25, 55);
    doc.text(new Date().toLocaleDateString(), 80, 55);
    doc.text("Online", 135, 55);

    // 🧑 User Section
    doc.setFontSize(13);
    doc.setTextColor(0, 102, 204);
    doc.text("USER DETAILS", 20, 75);

    doc.setTextColor(0, 0, 0);
    doc.setFontSize(11);
    doc.text(`Name: ${user?.displayName || "N/A"}`, 20, 82);
    doc.text(`Email: ${usersPaymentDetails?.email || "N/A"}`, 20, 87);
    doc.text(`UID: ${usersPaymentDetails?.uid || "N/A"}`, 20, 92);

    // 📦 Plan Box
    doc.setFillColor(245, 245, 245);
    doc.roundedRect(20, 100, 170, 50, 3, 3, "F");

    doc.setFontSize(13);
    doc.setTextColor(0, 102, 204);
    doc.text("PLAN DETAILS", 25, 110);

    doc.setFontSize(11);
    doc.setTextColor(0, 0, 0);
    doc.text(`Plan: ${usersPaymentDetails?.plan?.planName || "N/A"}`, 25, 120);
    doc.text(`Price: $ ${usersPaymentDetails?.plan?.price || "N/A"} / month`, 25, 130);
    doc.text(`Duration: ${usersPaymentDetails?.plan?.month || "N/A"} month`, 25, 140);

    // 💰 Summary Box
    doc.setFillColor(230, 255, 230); // light green
    doc.roundedRect(20, 160, 170, 40, 3, 3, "F");

    doc.setFontSize(13);
    doc.setTextColor(0, 153, 0);
    doc.text("PAYMENT SUMMARY", 25, 170);

    doc.setFontSize(11);
    doc.setTextColor(0, 0, 0);
    doc.text("VAT:", 25, 180);
    doc.text("0", 150, 180);

    doc.text("Total:", 25, 190);
    doc.setTextColor(0, 153, 0);
    doc.text(`$ ${usersPaymentDetails?.plan?.total || "N/A"}`, 150, 190);

    // ❤️ Footer
    doc.setTextColor(100);
    doc.setFontSize(11);
    doc.text("Thank you for your payment!", 105, 210, null, null, "center");

    doc.save("Payment_Receipt.pdf");
  };
  return (
    <div className="min-h-screen bg-[#0a0a0a] flex items-center justify-center px-5">
      <div className="bg-[#111] p-10 rounded-2xl text-center border border-green-500 shadow-[0_0_40px_rgba(34,197,94,0.3)] max-w-md w-full">
        {/* Icon */}
        <div className="text-green-400 text-6xl mb-4">✔</div>

        {/* Title */}
        <h1 className="text-3xl font-bold text-white mb-3">Payment Successful!</h1>

        {/* Description */}
        <p className="text-gray-400 mb-6">Your subscription has been activated successfully.</p>

        {/* Plan Info (optional) */}
        <div className="bg-black p-4 rounded-lg mb-6 border border-gray-700">
          <p className="text-sm text-gray-400">Plan Name</p>
          <p className="text-lg font-semibold text-orange-400">
            {usersPaymentDetails?.plan?.planName}
          </p>
        </div>

        {/* Buttons */}
        <div className="flex flex-col gap-3">
          <button
            onClick={handleDownloadPDF}
            className="w-full cursor-pointer py-3 rounded-lg font-semibold bg-gradient-to-r from-green-400 to-yellow-400 text-black hover:opacity-90"
          >
            Download Pdf
          </button>
          <button
            onClick={() => navigate("/dashboard")}
            className="w-full cursor-pointer py-3 rounded-lg font-semibold bg-gradient-to-r from-orange-400 to-yellow-400 text-black hover:opacity-90"
          >
            Go to Dashboard
          </button>

          <button
            onClick={() => navigate("/")}
            className="w-full cursor-pointer py-3 rounded-lg font-semibold bg-gray-800 text-white hover:bg-gray-700"
          >
            Back to Home
          </button>
        </div>
      </div>
    </div>
  );
};

export default PaymentSuccess;
